column1:
What does this code do?

class Pet:
    def __init__(self, name, animal_type, age):
        self.name = name
        self.animal_type = animal_type
        self.age = age

    def display_info(self):
        print(f"Name: {self.name}, Type: {self.animal_type}, Age: {self.age}")


class PetCare:
    def __init__(self):
        self.pets = []

    def add_pet(self, pet):
        self.pets.append(pet)

    def list_pets(self):
        if not self.pets:
            print("No pets in the system.")
            return
        for pet in self.pets:
            pet.display_info()

    def find_oldest_pet(self):
        if not self.pets:
            print("No pets in the system.")
            return None
        oldest_pet = max(self.pets, key=lambda pet: pet.age)
        return oldest_pet

# Example Usage
pet_care = PetCare()
pet1 = Pet("Buddy", "Dog", 3)
pet2 = Pet("Whiskers", "Cat", 5)
pet_care.add_pet(pet1)
pet_care.add_pet(pet2)
pet_care.list_pets()
oldest = pet_care.find_oldest_pet()
if oldest:
    print(f"The oldest pet is: {oldest.name}")

Explain this code: `def complex_function(data):
  results = []
  for item in data:
    if item % 2 == 0:
      results.append(item * 2)
    else:
      results.append(item + 1)
  return results`
